        ctUint128 ctC = MpcCore.offBoard(gtC);
        gtUint128 gtC2 = MpcCore.onBoard(ctC);
        uint128 resultC = MpcCore.decrypt(gtC2);
        require(resultC == c, "Value C test failed");

        return (resultA, resultB, resultC);
    }

