        gtUint256 currentBalance = userBalances256[msg.sender];

        gtUint256 newBalance = MpcCore.add(currentBalance, gtAmount);

        userBalances256[msg.sender] = newBalance;

        emit OperationPerformed(msg.sender, "add256");

